var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"많은 휴먼들이 신뢰와 신용을 혼동하지만, 저는 다릅니다.","JPN":"多くのヒューマンが信頼と信用を混同しますが、私は違います。","ENG":"Many humans confuse trust with credit, but not I.","TWN":"許多人類的誠信和信用都有問題，但我不一樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"신뢰는 주관적인 감정에서, 신용은 계량 가능한 경제활동 기록으로 매겨지죠.","JPN":"信頼は主観的な感情から、信用は計量可能な経済活動記録で得られるものです。","ENG":"Trust is based on subjective emotions whereas credit is determined by measurable economic activities.","TWN":"誠信是個人主觀感受，信用則是可以透過經濟行為去累積計算。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 0과 1로 사고하기 때문에 후자만을 사용하고 있습니다.","JPN":"私は0と1で思考するので、後者だけを使用しています。","ENG":"Since I reason only in ones and zeroes, I use the latter approach only.","TWN":"因為我的思考沒有情感成份，所以我只經營後者。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 휴먼들 중에는, 자신의 선택이 불러온 당연한 결과를 감당 못하는 자들도 많더군요.","JPN":"しかしヒューマンの中には、自分の選択が招いた当然の結果に耐えられない者も多いようです。","ENG":"But some humans seem unable to handle the obvious consequences of their decisions.","TWN":"不過人類當中，也有許多人無法承受選擇後帶來的結果。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"도박판에 가산을 탕진하거나. 사치에 빠져 빚더미에 앉거나. 술에 만취해야 살아 있다고 착각하거나.","JPN":"ギャンブルで財産を食いつぶしたり、贅沢に夢中になり首が回らなくなったり、酒に溺れていないと生きていると自覚できなくなったり。","ENG":"They would squander their wealth on gambling, end up in debt after indulging in an excessive lifestyle, or fool themselves into feeling alive only when intoxicated.","TWN":"像是在賭桌上散盡家產，或是買奢侈品買到欠一屁股債，抑或是整天買醉借酒澆愁。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"자기가 어떤 값어치를 지녔는지도 모르는 채로 썩어 가는 경우를, 저는 수없이 봐 왔습니다.","JPN":"自分がどんな価値を持っているのかも知らないまま腐っていくケースを、私は数え切れないほど見てきました。","ENG":"I've seen far too many of them rot away without even realizing their true worth.","TWN":"我看過很多的例子，不明白自己的價值，就這樣荒廢生命。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇기 때문에 저는 당신을 우수한 협력업체로 인식했습니다.","JPN":"そのため、私はあなたを優秀な協力会社と認識しました。","ENG":"As such, I've assessed you to be an outstanding partner.","TWN":"因此，我同意你是不錯的合作對象。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신이 저에게 무엇을 감추고 있는지, 어떤 의도로 저를 지원했는지는 상관없습니다.","JPN":"あなたが私に何を隠しているのか、どんな意図で私を呼び出したのかは関係ありません。","ENG":"I care not what you may be hiding from me or why you supported me.","TWN":"不管你對我有什麼隱瞞，或是有什麼意圖才幫助我的，這些都無所謂。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"맹물 같은 알파트릭스제 윤활유를 선호하는 취향은 감점 요인이긴 합니다만.","JPN":"水同然のアルファトリックス製の潤滑油を好むのは減点の要因ではありますが。","ENG":"Although your penchant for such a bland mess like Alphatrix lubricants is disconcerting…","TWN":"雖然喜歡阿爾法崔克斯製造的潤滑油，這一點有點扣分。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"자신이 빌린 물리력의 가치에 적정치 이상의 대우를 해 준다. 그것으로 충분합니다.","JPN":"自分が借りた物理力の価値に適正値以上の待遇をしてくれる。それだけで十分です。","ENG":"At least you know the price of the capability you wish to employ. That is good enough for me.","TWN":"但對於借來的助力願意給予超過預期的待遇，這樣便已足夠。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그러니 대견하다는 것처럼 어깨 토닥거리지 마십시오. 휴먼.","JPN":"だから偉いぞと褒めているかのように肩をとんとんするのはやめてください、ヒューマン。","ENG":"So please stop patting my shoulders like you're proud of me, human.","TWN":"所以人類，不用拍我的肩膀表示鼓勵。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"......손수건으로 눈물 훔치는 척도 하지 마십시오.","JPN":"……ハンカチで涙を拭うふりもしないでください。","ENG":"…and stop pretending to dab tears from your eyes with the handkerchief.","TWN":"……也不用假裝拿手帕擦眼淚。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};